package cmd

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/metaprompt"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"github.com/DocumentDrivenDX/ddx/internal/registry/defaultplugin"
	"github.com/spf13/cobra"
)

var initGitignoreRules = []string{
	// DDx runtime scratch — ignored
	".ddx/agent-logs/",
	".ddx/attachments/",
	".ddx/workers/",
	".ddx/exec-runs.d/",
	".ddx/.execute-bead-wt-*/",
	".ddx/executions/*/embedded/",
	".ddx/executions/**/scratch/",
	".ddx/*.lock",
	".ddx/*.tmp",
	".ddx/server.env",
	".ddx/server/",
	".ddx/run-state.json",
	".ddx/run-state/",
	// DDx tracked evidence — explicitly un-ignored under executions/
	"!.ddx/executions/",
	"!.ddx/executions/*/",
	"!.ddx/executions/*/prompt.md",
	"!.ddx/executions/*/manifest.json",
	"!.ddx/executions/*/result.json",
	"!.ddx/executions/*/checks.json",
	"!.ddx/executions/*/usage.json",
	// Skills target links — rewritten per-machine, not tracked
	".claude/skills/*/",
	".agents/skills/*/",
	// Other agent scratch
	".codex/",
	".agent/logs/",
	".agent/sessions/",
}

// InitOptions contains all configuration options for project initialization
type InitOptions struct {
	Force               bool   // Force initialization even if config exists
	NoGit               bool   // Skip git-related operations
	Silent              bool   // Suppress all output except errors
	SkipClaudeInjection bool   // Skip injecting meta-prompts into CLAUDE.md
	Repository          string // Custom repository URL (overrides default)
	Branch              string // Custom repository branch (overrides default)
	DDxVersion          string // Binary version to stamp into versions.yaml
}

// Command registration is now handled by command_factory.go
// This file contains the CLI interface layer and pure business logic functions

// InitResult contains the result of an initialization operation
type InitResult struct {
	ConfigCreated bool
	LibraryExists bool
	Config        *config.Config
}

// runInit implements the CLI interface layer for the init command
func (f *CommandFactory) runInit(cmd *cobra.Command, args []string) error {
	// --global mode: one-time machine setup, bypasses project checks.
	if globalMode, _ := cmd.Flags().GetBool("global"); globalMode {
		if err := initGlobal(); err != nil {
			cmd.SilenceUsage = true
			return err
		}
		if silent, _ := cmd.Flags().GetBool("silent"); !silent {
			_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx global machine setup complete.\n")
		}
		return nil
	}

	// Extract flags from cobra.Command
	initForce, _ := cmd.Flags().GetBool("force")
	initNoGit, _ := cmd.Flags().GetBool("no-git")
	initSilent, _ := cmd.Flags().GetBool("silent")
	initSkipClaude, _ := cmd.Flags().GetBool("skip-claude-injection")
	initRepository, _ := cmd.Flags().GetString("repository")
	initBranch, _ := cmd.Flags().GetString("branch")

	// Create options struct for business logic
	opts := InitOptions{
		Force:               initForce,
		NoGit:               initNoGit,
		Silent:              initSilent,
		SkipClaudeInjection: initSkipClaude,
		Repository:          initRepository,
		Branch:              initBranch,
		DDxVersion:          f.Version,
	}

	// Handle user output
	if !opts.Silent {
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "🚀 Initializing DDx in current project...\n")
		_, _ = fmt.Fprintln(cmd.OutOrStdout())
	}

	// Call pure business logic function
	_, err := initProject(f.WorkingDir, opts)
	if err != nil {
		cmd.SilenceUsage = true
		return err
	}

	// Handle user output based on results
	if !opts.Silent {
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx initialized successfully!\n")
		_, _ = fmt.Fprintln(cmd.OutOrStdout())
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "Next steps:\n")
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx install helix   - Install HELIX workflow (optional)\n")
		_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx doctor          - Check installation health\n")
		_, _ = fmt.Fprintln(cmd.OutOrStdout())
	}

	return nil
}

// initProject is the pure business logic function for project initialization
func initProject(workingDir string, opts InitOptions) (*InitResult, error) {
	result := &InitResult{}

	// Validate git repository unless --no-git flag is used
	if !opts.NoGit {
		if err := validateGitRepo(workingDir); err != nil {
			return nil, NewExitError(1, err.Error())
		}
	}

	// Guard against running inside an execute-bead context.
	if os.Getenv("DDX_EXECUTE_BEAD_ID") != "" {
		return nil, NewExitError(1,
			"ddx init cannot be run inside an execute-bead context (DDX_EXECUTE_BEAD_ID is set)")
	}
	// Guard against running inside an execute-bead worktree. These are isolated
	// execution environments under .ddx/.execute-bead-wt-*; running ddx init
	// inside one would overwrite the project's .ddx/ config and beads.jsonl.
	if isExecuteBeadWorktree(workingDir) {
		return nil, NewExitError(1,
			"ddx init cannot be run inside an execute-bead worktree (.ddx/.execute-bead-wt-*)")
	}

	// Guard against nested workspaces: if a parent directory already has a
	// .ddx/ workspace, refuse to create a second one in a subdirectory.
	// This prevents the split-tracker bug where commands from different
	// directories operate on different .ddx/beads.jsonl files.
	if parent := findParentDDxWorkspace(workingDir); parent != "" {
		return nil, NewExitError(1, fmt.Sprintf(
			".ddx/ workspace already exists at %s. "+
				"DDx anchors to the git repository root; run commands from any directory.",
			parent))
	}

	// Check if config already exists
	configPath := ddxroot.JoinProject(workingDir, "config.yaml")
	if _, err := os.Stat(configPath); err == nil {
		if !opts.Force {
			// Config exists and --force not used - exit code 2 per contract
			return nil, NewExitError(2, ".ddx/config.yaml already exists. Use --force to overwrite.")
		}
		// With --force flag, we proceed to overwrite without backup
	}

	// Check if library path exists using working directory
	cfg, err := config.LoadWithWorkingDir(workingDir)
	libraryExists := true
	if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
		libraryExists = false
	} else if _, err := os.Stat(filepath.Join(workingDir, cfg.Library.Path)); os.IsNotExist(err) {
		libraryExists = false
	}
	result.LibraryExists = libraryExists

	// Create configuration with defaults
	localConfig := createProjectConfig()

	// Apply default values (including repository settings)
	localConfig.ApplyDefaults()

	// Add validation during creation
	if err := validateConfiguration(localConfig); err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Configuration validation failed: %v", err))
	}

	// Try to load existing config to preserve settings (even if library doesn't exist yet)
	if cfg != nil && err == nil {
		// Note: Version is NOT copied - always upgrade to current version via ApplyDefaults
		// Copy library settings if they exist (unless overridden by flags)
		if cfg.Library != nil && localConfig.Library != nil {
			if cfg.Library.Path != "" {
				localConfig.Library.Path = cfg.Library.Path
			}
			if cfg.Library.Repository != nil && localConfig.Library.Repository != nil {
				// Only copy existing values if not overridden by flags
				if opts.Repository == "" && cfg.Library.Repository.URL != "" {
					localConfig.Library.Repository.URL = cfg.Library.Repository.URL
				}
				if opts.Branch == "" && cfg.Library.Repository.Branch != "" {
					localConfig.Library.Repository.Branch = cfg.Library.Repository.Branch
				}
			}
		}
	}

	// Apply flag overrides AFTER loading existing config (flags have highest priority)
	if opts.Repository != "" {
		if localConfig.Library == nil {
			localConfig.Library = &config.LibraryConfig{}
		}
		if localConfig.Library.Repository == nil {
			localConfig.Library.Repository = &config.RepositoryConfig{}
		}
		localConfig.Library.Repository.URL = opts.Repository
	}
	if opts.Branch != "" {
		if localConfig.Library == nil {
			localConfig.Library = &config.LibraryConfig{}
		}
		if localConfig.Library.Repository == nil {
			localConfig.Library.Repository = &config.RepositoryConfig{}
		}
		localConfig.Library.Repository.Branch = opts.Branch
	}

	// Create .ddx directory first
	localDDxPath := ddxroot.JoinProject(workingDir)
	if err := os.MkdirAll(localDDxPath, 0755); err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Failed to create .ddx directory: %v", err))
	}

	// Save local configuration using ConfigLoader
	loader, err := config.NewConfigLoaderWithWorkingDir(workingDir)
	if err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Failed to create config loader: %v", err))
	}
	if err := loader.SaveConfig(localConfig, ".ddx/config.yaml"); err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Failed to save configuration: %v", err))
	}
	result.ConfigCreated = true

	if err := ensureProjectGitignoreRules(workingDir, initGitignoreRules); err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Failed to update .gitignore: %v", err))
	}
	if !opts.NoGit {
		if err := untrackLegacyRunStateFiles(context.Background(), workingDir); err != nil {
			return nil, NewExitError(1, fmt.Sprintf("Failed to migrate legacy run-state tracking: %v", err))
		}
	}

package cmd

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"gopkg.in/yaml.v3"
)

// TestInitDoesNotCreateBootstrapDDxSkillMirror verifies the legacy
// .ddx/skills/ddx bootstrap mirror is no longer created. Skill outputs only
// live at the harness-visible paths .agents/skills/ddx and .claude/skills/ddx.
func TestInitDoesNotCreateBootstrapDDxSkillMirror(t *testing.T) {
	te := NewTestEnvironment(t, WithGitInit(false))
	_, err := te.RunCommand("init", "--no-git")
	require.NoError(t, err)

	// The bootstrap mirror path must not exist after init.
	bootstrapMirror := filepath.Join(te.Dir, ddxroot.DirName, "skills", "ddx")
	_, statErr := os.Stat(bootstrapMirror)
	assert.True(t, os.IsNotExist(statErr),
		".ddx/skills/ddx must not be created as a separate bootstrap mirror; got stat err=%v", statErr)
}

// TestInitProject_DoesNotInstallPlugins verifies that plain `ddx init` creates
// <project>/.ddx/ and the manifest but does not write .ddx/plugins/ddx,
// .agents/skills/ddx, .claude/skills/ddx, or any project-local plugins/ tree.
// Uses an isolated temp HOME/XDG fixture so the real user home is not touched.
func TestInitProject_DoesNotInstallPlugins(t *testing.T) {
	xdgDir := t.TempDir()
	homeDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)
	t.Setenv("HOME", homeDir)

	te := NewTestEnvironment(t, WithGitInit(false))
	_, err := te.RunCommand("init", "--no-git")
	require.NoError(t, err)

	// .ddx/ directory and config.yaml must exist.
	assert.DirExists(t, filepath.Join(te.Dir, ddxroot.DirName))
	assert.FileExists(t, filepath.Join(te.Dir, ddxroot.DirName, "config.yaml"))

	// No project-local plugins/ tree must be created.
	pluginsDir := filepath.Join(te.Dir, ddxroot.DirName, "plugins")
	_, statErr := os.Stat(pluginsDir)
	assert.True(t, os.IsNotExist(statErr),
		".ddx/plugins/ must not be created by plain ddx init; got stat err=%v", statErr)

	// No global plugins/ tree must be created.
	globalPluginsDir := filepath.Join(xdgDir, "ddx", "global", "plugins")
	_, gStatErr := os.Stat(globalPluginsDir)
	assert.True(t, os.IsNotExist(gStatErr),
		"global plugins/ must not be created by plain ddx init; got stat err=%v", gStatErr)

	// No agent-tier skill links must be installed in HOME.
	for _, surface := range []string{".agents/skills/ddx", ".claude/skills/ddx"} {
		skillDir := filepath.Join(homeDir, surface)
		_, statErr := os.Lstat(skillDir)
		assert.True(t, os.IsNotExist(statErr),
			"$HOME/%s must not be created by plain ddx init; got stat err=%v", surface, statErr)
	}
}

// TestInitProject_LeavesPluginsForLazyResolution verifies that after plain
// `ddx init`, registry.ResolvePlugin("ddx") falls through to the baked-in
// layer because no project-local or global plugin was installed.
func TestInitProject_LeavesPluginsForLazyResolution(t *testing.T) {
	// Isolate global DDx dir so a pre-existing global install doesn't interfere.
	xdgDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)

	te := NewTestEnvironment(t, WithGitInit(false))
	_, err := te.RunCommand("init", "--no-git")
	require.NoError(t, err)

	_, layer, resolveErr := registry.ResolvePlugin(context.Background(), te.Dir, "ddx")
	require.NoError(t, resolveErr)
	assert.Equal(t, "baked-in", layer,
		"ResolvePlugin must fall through to baked-in after plain init (no project-local or global install)")
}

// TestCleanupBootstrapSkills_RemovesStaleSkills verifies stale ddx-* skills are removed.
func TestCleanupBootstrapSkills_RemovesStaleSkills(t *testing.T) {
	targetDir := t.TempDir()

	// Create a stale ddx-* skill (no longer in bootstrap list)
	staleDir := filepath.Join(targetDir, "ddx-stale")
	require.NoError(t, os.MkdirAll(staleDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(staleDir, "SKILL.md"), []byte("# Stale"), 0o644))

	// Create a kept skill
	keepDir := filepath.Join(targetDir, "ddx-doctor")
	require.NoError(t, os.MkdirAll(keepDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(keepDir, "SKILL.md"), []byte("# Doctor"), 0o644))

	cleanupBootstrapSkills(targetDir, []string{"ddx-doctor"})

	_, err := os.Stat(staleDir)
	assert.True(t, os.IsNotExist(err), "stale ddx-* skill should be removed")
	assert.DirExists(t, keepDir, "kept ddx-* skill should remain")
}

// TestCleanupBootstrapSkills_PreservesNonDdxDirs verifies non-ddx- dirs are untouched.
func TestCleanupBootstrapSkills_PreservesNonDdxDirs(t *testing.T) {
	targetDir := t.TempDir()

	otherDir := filepath.Join(targetDir, "helix-align")
	require.NoError(t, os.MkdirAll(otherDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(otherDir, "SKILL.md"), []byte("# Helix"), 0o644))

	cleanupBootstrapSkills(targetDir, []string{"ddx-doctor"})

	assert.DirExists(t, otherDir, "non-ddx- skill should not be removed")
}

// TestCleanupBootstrapSkills_SkipsDirsWithoutSKILLMD verifies dirs without SKILL.md are untouched.
func TestCleanupBootstrapSkills_SkipsDirsWithoutSKILLMD(t *testing.T) {
	targetDir := t.TempDir()

	noSkillDir := filepath.Join(targetDir, "ddx-no-skill")
	require.NoError(t, os.MkdirAll(noSkillDir, 0o755))
	// no SKILL.md written

	cleanupBootstrapSkills(targetDir, []string{"ddx-doctor"})

	assert.DirExists(t, noSkillDir, "ddx-* dir without SKILL.md should not be removed")
}

// TestInitDoesNotTouchProjectSkillDirs verifies that plain `ddx init` does not
// create, modify, or delete any project-local agent-tier skill directories
// (.agents/skills/, .claude/skills/). Plugin install is deferred to lazy
// resolution; init is not allowed to touch the skills surface.
func TestInitDoesNotTouchProjectSkillDirs(t *testing.T) {
	te := NewTestEnvironment(t, WithGitInit(false))

	preExistingSkills := []string{"ddx-bead", "helix-align", "some-skill"}

	targetDirs := []string{
		filepath.Join(te.Dir, ".agents", "skills"),
		filepath.Join(te.Dir, ".claude", "skills"),
	}
	for _, dir := range targetDirs {
		for _, skill := range preExistingSkills {
			skillDir := filepath.Join(dir, skill)
			require.NoError(t, os.MkdirAll(skillDir, 0o755))
			require.NoError(t, os.WriteFile(filepath.Join(skillDir, "SKILL.md"), []byte("# "+skill), 0o644))
		}
	}

	_, err := te.RunCommand("init", "--no-git")
	require.NoError(t, err)

	// All pre-existing skills must remain untouched.
	for _, dir := range targetDirs {
		for _, skill := range preExistingSkills {
			skillFile := filepath.Join(dir, skill, "SKILL.md")
			assert.FileExists(t, skillFile, "pre-existing skill %s must not be removed from %s by plain init", skill, dir)
		}
	}

	// The ddx skill must NOT be installed by plain init.
	for _, dir := range targetDirs {
		ddxSkill := filepath.Join(dir, "ddx")
		_, statErr := os.Stat(ddxSkill)
		assert.True(t, os.IsNotExist(statErr),
			"plain init must not install ddx skill at %s (lazy resolution handles this)", ddxSkill)
	}
}

// TestGenerateAgentsMD_IncludesInteractiveStewardGuidance verifies that the
// generated AGENTS.md block includes interactive-steward mode, DDX_MODE
// precedence, mutation policy, and the tracker/merge/safety carve-out.
func TestGenerateAgentsMD_IncludesInteractiveStewardGuidance(t *testing.T) {
	workingDir := t.TempDir()

	generateAgentsMD(workingDir)

	agentsPath := filepath.Join(workingDir, "AGENTS.md")
	data, err := os.ReadFile(agentsPath)
	require.NoError(t, err)
	content := string(data)

	// AC1: Default Interactive Mode section naming all four modes
	assert.Contains(t, content, "interactive-steward", "interactive-steward mode missing")
	assert.Contains(t, content, "queue_steward", "queue_steward mode missing")
	assert.Contains(t, content, "bead_execution", "bead_execution mode missing")
	assert.Contains(t, content, "direct_user_implementation", "direct_user_implementation mode missing")
	assert.Contains(t, content, "review", "review mode missing")

	// AC2: DDX_MODE=bead_execution overrides only interactive default; never overrides policy
	assert.Contains(t, content, "DDX_MODE=bead_execution", "DDX_MODE=bead_execution precedence statement missing")
	assert.Contains(t, content, "never", "bead_execution override carve-out missing")
	assert.Contains(t, content, "tracker", "tracker carve-out missing")
	assert.Contains(t, content, "merge", "merge policy carve-out missing")
	assert.Contains(t, content, "safety", "safety carve-out missing")

	// AC3: mutation policy — non-mutating phases and explicit-verb requirement
	assert.Contains(t, content, "non-mutating", "non-mutating policy statement missing")
	assert.Contains(t, content, "Tracker mutation", "tracker mutation explicit-verb requirement missing")
	assert.Contains(t, content, "Code edits", "code edits explicit-intent requirement missing")
}

// TestGenerateAgentsMD_MergesWithMarkers verifies AGENTS.md injection preserves
// user content outside the DDx markers and updates content between them.
func TestGenerateAgentsMD_MergesWithMarkers(t *testing.T) {
	workingDir := t.TempDir()
	agentsPath := filepath.Join(workingDir, "AGENTS.md")

	// Pre-seed AGENTS.md with user content both before and after the DDx block
	userBefore := "# My Project\n\nUser content before the DDx block.\n\n"
	oldDdxBlock := agentsMarkerStart + "\nold ddx content\n" + agentsMarkerEnd + "\n"
	userAfter := "\n## More User Content\n\nUser content after the DDx block.\n"
	require.NoError(t, os.WriteFile(agentsPath, []byte(userBefore+oldDdxBlock+userAfter), 0644))

	generateAgentsMD(workingDir)

	data, err := os.ReadFile(agentsPath)
	require.NoError(t, err)
	content := string(data)

	// User content outside markers must survive
	assert.Contains(t, content, "User content before the DDx block.", "pre-block user content lost")
	assert.Contains(t, content, "User content after the DDx block.", "post-block user content lost")
	// New DDx block content must be present
	assert.Contains(t, content, "This project uses [DDx]", "new DDx block content not injected")
	// Block markers must still exist (exactly one pair)
	assert.Equal(t, 1, countOccurrences(content, agentsMarkerStart), "should have exactly one start marker")
	assert.Equal(t, 1, countOccurrences(content, agentsMarkerEnd), "should have exactly one end marker")

	// Running generateAgentsMD again must not duplicate the block
	generateAgentsMD(workingDir)
	data2, err := os.ReadFile(agentsPath)
	require.NoError(t, err)
	content2 := string(data2)
	assert.Equal(t, 1, countOccurrences(content2, agentsMarkerStart), "re-run duplicated start marker")
	assert.Equal(t, 1, countOccurrences(content2, agentsMarkerEnd), "re-run duplicated end marker")
}

// TestGenerateAgentsMD_CreatesWhenMissing verifies AGENTS.md is created if absent.
func TestGenerateAgentsMD_CreatesWhenMissing(t *testing.T) {
	workingDir := t.TempDir()
	agentsPath := filepath.Join(workingDir, "AGENTS.md")

	generateAgentsMD(workingDir)

	data, err := os.ReadFile(agentsPath)
	require.NoError(t, err)
	content := string(data)
	assert.Contains(t, content, agentsMarkerStart, "start marker missing")
	assert.Contains(t, content, agentsMarkerEnd, "end marker missing")
	assert.Contains(t, content, "This project uses [DDx]", "DDx content missing")
}

// TestGenerateAgentsMD_AppendsWhenMarkersAbsent verifies the block is appended
// when AGENTS.md exists but has no markers (user had AGENTS.md from another tool).
func TestGenerateAgentsMD_AppendsWhenMarkersAbsent(t *testing.T) {
	workingDir := t.TempDir()
	agentsPath := filepath.Join(workingDir, "AGENTS.md")

	userContent := "# My Project\n\nExisting AGENTS.md from another tool.\n"
	require.NoError(t, os.WriteFile(agentsPath, []byte(userContent), 0644))

	generateAgentsMD(workingDir)

	data, err := os.ReadFile(agentsPath)
	require.NoError(t, err)
	content := string(data)
	assert.Contains(t, content, "Existing AGENTS.md from another tool.", "existing content lost")
	assert.Contains(t, content, agentsMarkerStart, "start marker missing after append")
	assert.Contains(t, content, agentsMarkerEnd, "end marker missing after append")
}

// countOccurrences is a small test helper; we avoid strings.Count import noise here.
func countOccurrences(s, sub string) int {
	count := 0
	start := 0
	for {
		idx := indexFrom(s, sub, start)
		if idx == -1 {
			return count
		}
		count++
		start = idx + len(sub)
	}
}

func indexFrom(s, sub string, start int) int {
	if start > len(s) {
		return -1
	}
	rest := s[start:]
	for i := 0; i+len(sub) <= len(rest); i++ {
		if rest[i:i+len(sub)] == sub {
			return start + i
		}
	}
	return -1
}

// TestInitCommand tests the init command
func TestInitCommand(t *testing.T) {
	tests := []struct {
		name        string
		args        []string
		envOptions  []TestEnvOption
		setup       func(t *testing.T, te *TestEnvironment)
		validate    func(t *testing.T, te *TestEnvironment, output string, err error)
		expectError bool
	}{
		{
			name:       "basic initialization",
			args:       []string{"init", "--no-git"},

	RetryCooldownCount             int                          `json:"retry_cooldown_count"`
	NextRetryAfter                 string                       `json:"next_retry_after,omitempty"`
	ExecutionIneligibleCount       int                          `json:"execution_ineligible_count"`
	SupersededCount                int                          `json:"superseded_count"`
	SkippedEpicsCount              int                          `json:"skipped_epics_count"`
	EpicClosureCandidatesCount     int                          `json:"epic_closure_candidates_count"`
}

// HumanReviewBlockerSnapshot reports one open human-review blocker and how
// many active downstream beads are transitively waiting on it.
type HumanReviewBlockerSnapshot struct {
	ID                     string `json:"id"`
	Title                  string `json:"title"`
	Priority               int    `json:"priority"`
	DownstreamBlockedCount int    `json:"downstream_blocked_count"`
}

// ProgressEvent is the FEAT-006 structured progress event. It is defined
// separately in the server package (server.ProgressEvent); this alias lets
// the agent package emit events without importing the server package.
// The field names and types are identical — the server package deserialises
// these directly from the channel.
//
// Terminal phases: done, preserved, failed.
type ProgressEvent struct {
	EventID   string    `json:"event_id"`
